INSERT INTO i18n_message (
    message_type,
    message_key,
    `language`,
    message,
    created_time,
    creator
)
SELECT
    message_type,
    message_key,
    'pt-BR' AS `language`,
    message,
    created_time,
    creator
FROM i18n_message
WHERE `language` = 'en-US'
  AND message_key NOT IN (
    SELECT message_key FROM i18n_message WHERE `language` = 'pt-BR'
);

